import java.io.*;

public class SecureCommandExecution {
    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = br.readLine();

            // Validate and sanitize user input
            if (isValidCommand(command)) {
                // Safe code - using ProcessBuilder with validated command
                Process process = new ProcessBuilder(command.split(" ")).start();

                BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
            } else {
                System.out.println("Invalid command input");
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static boolean isValidCommand(String command) {
        // Implement your validation logic here
        // Example: Restricting to specific commands or patterns
        return command.matches("[a-zA-Z0-9]+");
    }
}
